/**
 * DANK Cannabis Club — OTP Verification v3.0
 * Verifies OTP generated by signup.js (stored in sessionStorage)
 * Requires: config.js → supabase.js → auth.js
 */
'use strict';

const OTP_LENGTH  = 6;
const RESEND_WAIT = 60;

let _pendingEmail = '';
let _staffName    = '';
let _resendInterval = null;
let _expiryInterval = null;
let _resendLeft   = 0;
let _isVerifying  = false;

window.addEventListener('DOMContentLoaded', init);

function init() {
  _pendingEmail = sessionStorage.getItem('dank_pending_email') || '';
  _staffName    = sessionStorage.getItem('dank_staff_name')    || '';

  if (!_pendingEmail) {
    showAlert('ไม่พบข้อมูลการสมัคร — กำลังพาไปหน้า Signup...');
    setTimeout(() => window.location.replace(AUTH_CONFIG.signupPage), 2000);
    return;
  }

  const emailDisplay = document.getElementById('emailDisplay');
  if (emailDisplay) {
    const managerEmail = window.EMAILJS_CONFIG?.managerEmail || 'dankclubbkk@gmail.com';
    emailDisplay.textContent = managerEmail;
  }

  wireInputs();
  startExpiryCountdown();
  startResendCooldown();
  document.getElementById('otp0')?.focus();
}

// ── OTP INPUT ─────────────────────────────────────────────────────
function wireInputs() {
  for (let i = 0; i < OTP_LENGTH; i++) {
    const input = document.getElementById(`otp${i}`);
    if (!input) continue;
    input.addEventListener('input',   e => onBoxInput(e, i));
    input.addEventListener('keydown', e => onBoxKeydown(e, i));
    input.addEventListener('paste',   onPaste);
  }
}

function onBoxInput(e, idx) {
  const val = e.target.value.replace(/\D/g, '');
  e.target.value = val.slice(-1);
  if (val && idx < OTP_LENGTH - 1) document.getElementById(`otp${idx + 1}`)?.focus();
  autoSubmitIfComplete();
}

function onBoxKeydown(e, idx) {
  if (e.key === 'Backspace' && !e.target.value && idx > 0)
    document.getElementById(`otp${idx - 1}`)?.focus();
  if (e.key === 'ArrowLeft'  && idx > 0)              document.getElementById(`otp${idx - 1}`)?.focus();
  if (e.key === 'ArrowRight' && idx < OTP_LENGTH - 1) document.getElementById(`otp${idx + 1}`)?.focus();
}

function onPaste(e) {
  e.preventDefault();
  const text = (e.clipboardData || window.clipboardData)
    .getData('text').replace(/\D/g, '').slice(0, OTP_LENGTH);
  for (let i = 0; i < OTP_LENGTH; i++) {
    const box = document.getElementById(`otp${i}`);
    if (box) box.value = text[i] || '';
  }
  document.getElementById(`otp${Math.min(text.length, OTP_LENGTH - 1)}`)?.focus();
  autoSubmitIfComplete();
}

function getOtpValue() {
  return Array.from({ length: OTP_LENGTH }, (_, i) =>
    (document.getElementById(`otp${i}`)?.value || '')
  ).join('');
}

function autoSubmitIfComplete() {
  if (getOtpValue().length === OTP_LENGTH && !_isVerifying) verifyOtp();
}

// ── VERIFY ────────────────────────────────────────────────────────
async function verifyOtp() {
  if (_isVerifying) return;
  const entered = getOtpValue();
  if (entered.length !== OTP_LENGTH) { showAlert('กรุณากรอก OTP 6 หลักให้ครบ'); return; }

  _isVerifying = true;
  setLoading(true);
  hideAlert();

  // ตรวจสอบ OTP จาก sessionStorage
  const storedOtp    = sessionStorage.getItem('dank_otp_code')   || '';
  const storedExpiry = parseInt(sessionStorage.getItem('dank_otp_expiry') || '0');

  if (Date.now() > storedExpiry) {
    showAlert('⏰ OTP หมดอายุแล้ว — กดส่งใหม่');
    setLoading(false);
    _isVerifying = false;
    return;
  }

  if (entered !== storedOtp) {
    showAlert('รหัส OTP ไม่ถูกต้อง — ลองใหม่');
    setLoading(false);
    _isVerifying = false;
    clearBoxes();
    document.getElementById('otp0')?.focus();
    return;
  }

  // OTP ถูกต้อง → Login ทันที
  const emailEl = _pendingEmail;
  const pw = sessionStorage.getItem('dank_pending_pw') || '';

  // ล้าง OTP ออกจาก sessionStorage
  sessionStorage.removeItem('dank_otp_code');
  sessionStorage.removeItem('dank_otp_expiry');
  sessionStorage.removeItem('dank_staff_name');

  stopTimers();
  showAlert('✅ ยืนยันสำเร็จ! กำลังเข้าสู่ระบบ...', true);
  setTimeout(() => window.location.replace(AUTH_CONFIG.dashPage), 1200);
}

// ── RESEND ───────────────────────────────────────────────────────
async function resendOtp() {
  if (_resendLeft > 0) return;

  const btn = document.getElementById('resendBtn');
  if (btn) btn.disabled = true;
  showAlert('⏳ กำลังส่ง OTP ใหม่...', true);

  // Generate OTP ใหม่
  const otp = String(Math.floor(100000 + Math.random() * 900000));
  const otpExpiry = Date.now() + 10 * 60 * 1000;
  sessionStorage.setItem('dank_otp_code',   otp);
  sessionStorage.setItem('dank_otp_expiry', otpExpiry);

  try {
    const cfg = window.EMAILJS_CONFIG;
    emailjs.init(cfg.publicKey);
    const result = await emailjs.send(cfg.serviceId, cfg.templateId, {
      staff_name:  _staffName || _pendingEmail,
      staff_email: _pendingEmail,
      otp_code:    otp,
      to_email:    cfg.managerEmail,
    });

    if (result.status === 200) {
      showAlert('✅ ส่ง OTP ใหม่ไปที่ผู้จัดการแล้ว', true);
      enableBoxes();
      clearBoxes();
      document.getElementById('otp0')?.focus();
    } else {
      showAlert('ส่ง OTP ไม่ได้ — ลองใหม่');
    }
  } catch (err) {
    console.error('[DANK] resend EmailJS:', err);
    showAlert('ส่ง OTP ไม่ได้ — ตรวจสอบการเชื่อมต่อ');
  }

  startResendCooldown();
}

// ── TIMERS ───────────────────────────────────────────────────────
function startResendCooldown() {
  _resendLeft = RESEND_WAIT;
  const btn     = document.getElementById('resendBtn');
  const timerEl = document.getElementById('resendTimer');
  if (btn) btn.disabled = true;
  if (timerEl) timerEl.textContent = `(${_resendLeft}s)`;

  clearInterval(_resendInterval);
  _resendInterval = setInterval(() => {
    _resendLeft--;
    if (timerEl) timerEl.textContent = _resendLeft > 0 ? `(${_resendLeft}s)` : '';
    if (btn) btn.disabled = _resendLeft > 0;
    if (_resendLeft <= 0) { clearInterval(_resendInterval); _resendInterval = null; }
  }, 1000);
}

function startExpiryCountdown() {
  clearInterval(_expiryInterval);
  const el = document.getElementById('expiryTimer');
  let left = Math.max(0, Math.floor((parseInt(sessionStorage.getItem('dank_otp_expiry') || '0') - Date.now()) / 1000));

  _expiryInterval = setInterval(() => {
    left--;
    if (el) {
      const m = Math.floor(left / 60);
      const s = String(left % 60).padStart(2, '0');
      el.textContent = `${m < 10 ? '0' : ''}${m}:${s}`;
    }
    if (left <= 0) {
      clearInterval(_expiryInterval);
      showAlert('⏰ OTP หมดอายุแล้ว — กดส่งใหม่');
      disableBoxes();
    }
  }, 1000);
}

function stopTimers() {
  clearInterval(_resendInterval);
  clearInterval(_expiryInterval);
}

// ── BOX & UI HELPERS ─────────────────────────────────────────────
function clearBoxes() {
  for (let i = 0; i < OTP_LENGTH; i++) {
    const box = document.getElementById(`otp${i}`);
    if (box) box.value = '';
  }
}
function disableBoxes() {
  for (let i = 0; i < OTP_LENGTH; i++) {
    const box = document.getElementById(`otp${i}`);
    if (box) { box.disabled = true; box.style.opacity = '0.5'; }
  }
}
function enableBoxes() {
  for (let i = 0; i < OTP_LENGTH; i++) {
    const box = document.getElementById(`otp${i}`);
    if (box) { box.disabled = false; box.style.opacity = '1'; }
  }
  _isVerifying = false;
}
function setLoading(on) {
  const btn     = document.getElementById('verifyBtn');
  const label   = document.getElementById('verifyBtnLabel');
  const spinner = document.getElementById('verifySpinner');
  if (btn)     btn.disabled       = on;
  if (label)   label.textContent  = on ? 'กำลังยืนยัน...' : '✅ ยืนยัน OTP';
  if (spinner) spinner.style.display = on ? 'block' : 'none';
}
function showAlert(msg, success = false) {
  const el    = document.getElementById('otpAlert');
  const msgEl = document.getElementById('otpAlertMsg');
  if (el)    el.className = 'auth-alert show' + (success ? ' auth-success' : '');
  if (msgEl) msgEl.textContent = msg;
}
function hideAlert() {
  const el = document.getElementById('otpAlert');
  if (el) el.className = 'auth-alert';
}
